    56→		webIDE = devmachinemodel.WebIDEJupyter
    57→	}
    58→
    59→	// 构建基础卷（emptyDir）
    60→	volumes := buildVolumes(webIDE)
    61→
    62→	// 添加存储卷（PVC）
    63→	storageVolumes := buildStorageVolumes(request.Namespace, request.Name, request.Storage)
    64→	volumes = append(volumes, storageVolumes...)
    65→
    66→	return corev1.PodSpec{
    67→		SchedulerName:  volcanoSchedulerName,
    68→		NodeSelector:   request.NodeSelector,
    69→		Volumes:        volumes,
    70→		InitContainers: buildInitContainers(initContainerImage, webIDE),
    71→		Containers:     buildContainers(request),
    72→	}
    73→}
